var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"좌익 쪽 놈들의 퇴로를 차단했습니다!","JPN":"左翼のやつらの退路を遮断しました！","ENG":"The left flank has been sealed off!","TWN":"已經封鎖了左翼那些傢伙的退路！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"우익도 마찬가지입니다! 한점으로 몰아넣었으니 신호만 주십시오!","JPN":"右翼も同様です！　一か所に追い込みました！　合図だけください！","ENG":"Same with the right! We've driven them all into one spot, just give the signal!","TWN":"右翼也是一樣的！已經逼到一個點上了，請給我訊號！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아직 움직이는 놈들이 있습니다! 진형 사이의 틈을 넓히면 안 돼요!","JPN":"まだ動いているやつらがいます！　陣形に隙を作らないでください！","ENG":"Some are still moving! Don't let any gaps form in the formation!","TWN":"還有敵人在行動！不能讓陣型之間的間隙擴大！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"어…?","JPN":"あっ……？","ENG":"Huh...?","TWN":"呃…？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"비, 비행형 몇 마리가 빠져나왔어!","JPN":"ひ、飛行型が何匹か抜け出たぞ！","ENG":"A-a few fliers got through!","TWN":"有幾隻飛行型的怪物逃出來了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"움직이지 마! 진형이 붕괴되면 사상자만 늘어나!!","JPN":"動くな！　陣形が崩れると死傷者が増える！！","ENG":"Hold your positions! Break the formation and we'll lose more lives!!","TWN":"不要動！陣型一旦潰散，傷亡只會增加！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"치잇…!!","JPN":"ちっ……！！","ENG":"Tch...!!","TWN":"嘖…！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"지금입니다, 무구를 개방하세요!","JPN":"今です、武具を開放しなさい！","ENG":"Now! Unleash your Armaments!","TWN":"就是現在，開放武具吧！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저건, 부단장의 스콜피오 랜스?","JPN":"あれは、副団長のスコルピオランス？","ENG":"That's... Deputy's Scorpio Lance?","TWN":"那是，副團長的天蠍長槍？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만, 저 형태는…!!","JPN":"でも、あの形は……！！","ENG":"But that form...!!","TWN":"但是，那種形態是…！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그래서, 내가 어? 혼자서 괴수 다섯 마리를 쓰러트렸다니까?","JPN":"それで、俺がさ？　1人で怪獣を5匹は倒したんだよ。","ENG":"I'm telling you, I took down five C.O.s by myself, okay?","TWN":"所以，我一個人打倒了五隻怪獸，你信嗎？"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"우리가 이렇게 술 먹고 있는 것도~? 다 내 덕분… 끄억!","JPN":"こうやって酒飲んでるのもな～？　全部俺のおかげ……げぷっ！","ENG":"So the fact that we're all drinking now? Totally thanks to me– *Burp*","TWN":"我們能這樣喝酒～？都是我的功勞…嗝！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"하하! 딜란 경 좀 봐! 아주 그냥 확실히 취했어!","JPN":"はは！　ディラン卿が完全に酔っぱらってる！","ENG":"Haha! Look at Sir Dylan! He's totally drunk!","TWN":"哈哈！看看迪蘭！他真是醉得徹底啊！"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"고작 세 잔에 곯아떨어지다니. 1번대도 별거 없구만?","JPN":"3杯で酔いつぶれるなんて、第1番隊も大したことねえな？","ENG":"Three drinks and he's out cold? So much for Squad 1's pride!","TWN":"才三杯就醉倒了。第一小隊也沒什麼嘛？"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"우쒸! 지금 말 다 했어?!","JPN":"おら！　今何って言った！！","ENG":"Hey! You wanna say that again?!","TWN":"可惡！你說完了嗎？"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무슨 일이길래 그리 오작동 난 전쟁 골렘 같은 표정을 짓고 계십니까?","JPN":"どうして誤作動してしまったウォーゴーレムのようなお顔をされているのですか？","ENG":"What's with that stiff face? You look like a broken war golem.","TWN":"發生什麼事了，怎麼擺出一副戰爭傀儡故障的表情？"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"술이 입에 맞지 않으신다면, 경께서 혁혁한 공을 세우셨으니 제 비장의 포도주라도 대접하겠습니다.","JPN":"お酒が口に合わないのなら、卿には輝かしい戦功を立てていただきましたし、私のとっておきのブドウ酒を開けますよ。","ENG":"If the drinks aren't to your liking, you did perform admirably. I could offer you my best wine.","TWN":"如果酒不合你的口味，你立下了赫赫戰功，我會奉上我的珍藏葡萄酒以示敬意。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"전 미성년자입니다.","JPN":"私は未成年です。","ENG":"I'm not old enough to drink.","TWN":"我是未成年人。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 포도주스는 없는데 곤란하네요.","JPN":"あら。ブドウジュースはありませんし、困りましたね。","ENG":"Oh dear. There is no grape juice on hand.","TWN":"哎呀，沒有葡萄汁，這可麻煩了。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"함께 잔을 나누고 싶었는데, 유감스럽게도 혼자 즐겨야겠군요.","JPN":"一緒に盃をかわしたかったのですが、一人で飲むしかありませんね。","ENG":"I was hoping to share a toast, but I suppose I'll have to drink alone.","TWN":"本想與你共飲一杯，遺憾的是只能獨自享受了。"},"stage":{"bg":"CAMP_NIGHT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};